_HEX = set("0123456789abcdef")

def _table_name(ref: str) -> str:
    s = (ref or "").split("/")[-1]
    if len(s) > 9 and s[8] == "_" and all(c in _HEX for c in s[:8].lower()):
        s = s[9:]
    s = s.split(".")[0]
    return s.upper()

_ORDER = ["FI", "CO", "AA", "TR", "MM", "WM", "SD", "HCM"]

def build_sap_glossary(table_names) -> str:
    mods = []
    for t in table_names or []:
        code = TABLE_MODULE.get(_table_name(t))
        if code and code not in mods:
            mods.append(code)
    mods = [m for m in _ORDER if m in mods] or [m for m in _ORDER if m in GLOSSARY_BY_MODULE]
    blocks = [SAP_DISAMBIGUATION] + [GLOSSARY_BY_MODULE[m] for m in mods if m in GLOSSARY_BY_MODULE]
    return "\n\n" + "\n\n".join(blocks) + "\n"
